@spec tm_authoring_forward_spec  src=tests/specs/tm_authoring_forward_spec.lua  loc=182  sha=652cbb1  cases=8
@exercises trackerManager (h.tm), midiManager (h.fm)
@surface   tm:addEvent, tm:flush, fm:dump, tm:getChannel, tm:assignEvent
@harness   mk{seed.notes, seed.length}

# Intent
  Two-frame boundary at um: caller passes evt.ppq / update.ppq in the
  logical frame; um stamps ppqL with that value and overwrites ppq
  with raw via fromLogical(ppq) + delay before mm sees the record.

# Cases
  @case 'addEvent: caller ppq is logical; um derives raw under swing and stamps ppqL'  [harness]  @ 13-33
  @case 'addEvent: delay shifts raw, leaves ppqL on the logical row'  [harness]  @ 37-57
  @case 'assignEvent: update.ppq is logical; raw derives via swing, ppqL restamped'  [harness]  @ 61-80
  @case 'assignEvent: delay-only edit recomputes raw forward from evt.ppqL under swing'  [harness]  @ 84-104
  @case 'addEvent: caller authors endppq=util.OPEN; tm derives the tail, caller sets no endppqL'  [harness]  @ 110-119
  @case 'addEvent: open tail renders clipped to the next same-pitch onset, intent stays OPEN'  [harness]  @ 123-138
  @case 'assignEvent: endppq=util.OPEN reopens a finite note (caller sets no endppqL)'  [harness]  @ 142-154
  @case 'assignEvent: endppq past take-end is clamped to takeLen; endppqL keeps the authored intent'  [harness]  @ 164-180

# Uses (outbound edges)
  @use call tm:addEvent  @ 22,46,113,126,128
  @use call tm:flush  @ 27,51,75,99,115,130,150,172
  @use call fm:dump  @ 29,53,77,101,174
  @use call tm:getChannel  @ 73,97,116,132,148,151,170,178
  @use call tm:assignEvent  @ 74,98,149,171

